//! Whisper config + tensor-name resolution for the Pneuma voice mesh.
//!
//! Reference: arXiv 2212.04356 (Whisper — Robust Speech Recognition via
//! Large-Scale Weak Supervision, Radford et al. 2022).
//! https://arxiv.org/abs/2212.04356
//!
//! This file is the Agent-D deliverable in the Pneuma cross-file contract
//! (`PNEUMA_CONTRACTS.md`). It owns three things:
//!
//! 1. [`WhisperConfig`] — the structural dimensions every other Whisper
//!    component reads (encoder, decoder, WASM bindings).
//! 2. [`parse_whisper_config`] — tolerant reader that pulls those dims out of
//!    a `.knot` metadata `config` block (HF Whisper `config.json` shape, with
//!    snake_case _or_ camelCase keys accepted).
//! 3. [`whisper_tensor_name`] + [`WhisperTensorAddresses`] — the canonical
//!    tensor naming scheme used by the `.knot` weight loader, plus a
//!    pre-computed address book so the hot inference path doesn't pay
//!    `format!` cost on every tensor fetch.
//!
//! Names mirror the table in the contracts doc:
//!   `encoder_blk_{i}_<role>`, `decoder_blk_{i}_<role>`,
//!   `encoder_<role>` / `decoder_<role>` for stage-level tensors.

use serde_json::Value;

// ─────────────────────────────────────────────────────────────────────────────
// WhisperConfig
// ─────────────────────────────────────────────────────────────────────────────

/// Structural configuration for an OpenAI Whisper model.
///
/// All sizes are in elements (not bytes). Field meanings track HF's
/// `WhisperConfig` so that conversion from `config.json` is mechanical.
#[derive(Debug, Clone, PartialEq)]
pub struct WhisperConfig {
    // Audio input ────────────────────────────────────────────────────────────
    /// Number of mel filterbank channels. 80 for every released Whisper.
    pub n_mels: usize,
    /// Encoded audio context length (post Conv1d stride-2). 1500 always.
    pub n_audio_ctx: usize,

    // Encoder ────────────────────────────────────────────────────────────────
    /// Number of transformer blocks in the audio encoder.
    pub encoder_layers: usize,
    /// Hidden dimension of the encoder (`d_model` in HF).
    pub encoder_hidden_dim: usize,
    /// Number of attention heads in each encoder block.
    pub encoder_heads: usize,
    /// MLP intermediate (FFN) size — typically `4 * encoder_hidden_dim`.
    pub encoder_intermediate_size: usize,

    // Decoder ────────────────────────────────────────────────────────────────
    /// Number of transformer blocks in the text decoder.
    pub decoder_layers: usize,
    /// Hidden dimension of the decoder (matches encoder for Whisper).
    pub decoder_hidden_dim: usize,
    /// Number of attention heads in each decoder block.
    pub decoder_heads: usize,
    /// MLP intermediate (FFN) size for the decoder.
    pub decoder_intermediate_size: usize,
    /// Maximum decoded sequence length (`max_target_positions`). 448.
    pub n_text_ctx: usize,
    /// Vocabulary size. 51865 multilingual, 51864 en-only.
    pub vocab_size: usize,

    /// LayerNorm epsilon. 1e-5 for all Whisper variants.
    pub eps: f32,
}

impl Default for WhisperConfig {
    /// Defaults to whisper-tiny (the smallest released Whisper variant).
    fn default() -> Self {
        Self {
            n_mels: 80,
            n_audio_ctx: 1500,
            encoder_layers: 4,
            encoder_hidden_dim: 384,
            encoder_heads: 6,
            encoder_intermediate_size: 1536,
            decoder_layers: 4,
            decoder_hidden_dim: 384,
            decoder_heads: 6,
            decoder_intermediate_size: 1536,
            n_text_ctx: 448,
            vocab_size: 51865,
            eps: 1e-5,
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// parse_whisper_config
// ─────────────────────────────────────────────────────────────────────────────

/// Read a value from a JSON object under any of the supplied key aliases.
///
/// Used so we can accept HF's snake_case (`encoder_layers`) and the alternate
/// camelCase emitted by some Whisper conversion pipelines (`encoderLayers`).
fn pick<'a>(obj: &'a Value, keys: &[&str]) -> Option<&'a Value> {
    for k in keys {
        if let Some(v) = obj.get(k) {
            if !v.is_null() {
                return Some(v);
            }
        }
    }
    None
}

/// Read a usize from a JSON value, returning `None` if it isn't an unsigned int.
fn as_usize(v: &Value) -> Option<usize> {
    v.as_u64().map(|n| n as usize)
}

/// Parse a [`WhisperConfig`] out of a `.knot` metadata blob.
///
/// `meta` is the full metadata JSON (the same `serde_json::Value` returned by
/// `loader::parse_*` helpers). The function looks for a top-level `config`
/// object whose fields mirror HF's Whisper `config.json`. Missing fields fall
/// back to whisper-tiny defaults so a partial or sparsely-encoded knot still
/// produces a usable config — the encoder/decoder will validate against the
/// loaded tensor shapes downstream.
///
/// Accepts both snake_case (HF-native) and camelCase keys.
pub fn parse_whisper_config(meta: &Value) -> Result<WhisperConfig, String> {
    let cfg = meta.get("config").unwrap_or(meta);
    if !cfg.is_object() {
        return Err("parse_whisper_config: `config` is not a JSON object".to_string());
    }

    let d = WhisperConfig::default();

    let encoder_hidden_dim = pick(
        cfg,
        &[
            "d_model",
            "dModel",
            "encoder_hidden_dim",
            "encoderHiddenDim",
        ],
    )
    .and_then(as_usize)
    .unwrap_or(d.encoder_hidden_dim);

    // Decoder shares d_model with encoder unless explicitly overridden.
    let decoder_hidden_dim = pick(cfg, &["decoder_hidden_dim", "decoderHiddenDim"])
        .and_then(as_usize)
        .unwrap_or(encoder_hidden_dim);

    let encoder_intermediate_size = pick(
        cfg,
        &[
            "encoder_ffn_dim",
            "encoderFfnDim",
            "encoder_intermediate_size",
            "encoderIntermediateSize",
        ],
    )
    .and_then(as_usize)
    .unwrap_or(4 * encoder_hidden_dim);

    let decoder_intermediate_size = pick(
        cfg,
        &[
            "decoder_ffn_dim",
            "decoderFfnDim",
            "decoder_intermediate_size",
            "decoderIntermediateSize",
        ],
    )
    .and_then(as_usize)
    .unwrap_or(4 * decoder_hidden_dim);

    let cfg = WhisperConfig {
        n_mels: pick(cfg, &["num_mel_bins", "numMelBins", "n_mels", "nMels"])
            .and_then(as_usize)
            .unwrap_or(d.n_mels),
        n_audio_ctx: pick(
            cfg,
            &[
                "max_source_positions",
                "maxSourcePositions",
                "n_audio_ctx",
                "nAudioCtx",
            ],
        )
        .and_then(as_usize)
        .unwrap_or(d.n_audio_ctx),

        encoder_layers: pick(cfg, &["encoder_layers", "encoderLayers"])
            .and_then(as_usize)
            .unwrap_or(d.encoder_layers),
        encoder_hidden_dim,
        encoder_heads: pick(
            cfg,
            &[
                "encoder_attention_heads",
                "encoderAttentionHeads",
                "encoder_heads",
            ],
        )
        .and_then(as_usize)
        .unwrap_or(d.encoder_heads),
        encoder_intermediate_size,

        decoder_layers: pick(cfg, &["decoder_layers", "decoderLayers"])
            .and_then(as_usize)
            .unwrap_or(d.decoder_layers),
        decoder_hidden_dim,
        decoder_heads: pick(
            cfg,
            &[
                "decoder_attention_heads",
                "decoderAttentionHeads",
                "decoder_heads",
            ],
        )
        .and_then(as_usize)
        .unwrap_or(d.decoder_heads),
        decoder_intermediate_size,

        n_text_ctx: pick(
            cfg,
            &[
                "max_target_positions",
                "maxTargetPositions",
                "n_text_ctx",
                "nTextCtx",
            ],
        )
        .and_then(as_usize)
        .unwrap_or(d.n_text_ctx),
        vocab_size: pick(cfg, &["vocab_size", "vocabSize"])
            .and_then(as_usize)
            .unwrap_or(d.vocab_size),

        eps: pick(cfg, &["layer_norm_eps", "layerNormEps", "eps"])
            .and_then(|v| v.as_f64())
            .map(|n| n as f32)
            .unwrap_or(d.eps),
    };

    Ok(cfg)
}

// ─────────────────────────────────────────────────────────────────────────────
// Tensor name composition
// ─────────────────────────────────────────────────────────────────────────────

/// Compose a `.knot` tensor name for a Whisper weight.
///
/// Mirrors the table in `PNEUMA_CONTRACTS.md`:
///
/// - `whisper_tensor_name("encoder", Some(0), "attn_q.weight")`
///   → `"encoder_blk_0_attn_q.weight"`
/// - `whisper_tensor_name("encoder", None, "ln_final.bias")`
///   → `"encoder_ln_final.bias"`
/// - `whisper_tensor_name("decoder", Some(3), "cross_v.weight")`
///   → `"decoder_blk_3_cross_v.weight"`
pub fn whisper_tensor_name(stage: &str, layer: Option<usize>, role: &str) -> String {
    match layer {
        Some(i) => format!("{}_blk_{}_{}", stage, i, role),
        None => format!("{}_{}", stage, role),
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Pre-computed address book
// ─────────────────────────────────────────────────────────────────────────────

/// Per-encoder-block tensor roles, in the order the forward pass needs them.
/// Whisper's K projection has no bias (matches the HF reference), so it is
/// the only Q/K/V matmul without a paired `.bias` entry.
pub const ENCODER_BLOCK_ROLES: &[&str] = &[
    "attn_q.weight",
    "attn_q.bias",
    "attn_k.weight",
    "attn_v.weight",
    "attn_v.bias",
    "attn_out.weight",
    "attn_out.bias",
    "ln1.weight",
    "ln1.bias",
    "mlp_fc1.weight",
    "mlp_fc1.bias",
    "mlp_fc2.weight",
    "mlp_fc2.bias",
    "ln2.weight",
    "ln2.bias",
];

/// Per-decoder-block tensor roles. Same K-no-bias rule applies to both the
/// self-attention and cross-attention K projections. The decoder also carries
/// a pre-MLP LayerNorm (`mlp_ln`) on top of the per-attention LNs.
pub const DECODER_BLOCK_ROLES: &[&str] = &[
    "self_q.weight",
    "self_q.bias",
    "self_k.weight",
    "self_v.weight",
    "self_v.bias",
    "self_out.weight",
    "self_out.bias",
    "self_ln.weight",
    "self_ln.bias",
    "cross_q.weight",
    "cross_q.bias",
    "cross_k.weight",
    "cross_v.weight",
    "cross_v.bias",
    "cross_out.weight",
    "cross_out.bias",
    "cross_ln.weight",
    "cross_ln.bias",
    "mlp_fc1.weight",
    "mlp_fc1.bias",
    "mlp_fc2.weight",
    "mlp_fc2.bias",
    "mlp_ln.weight",
    "mlp_ln.bias",
];

/// Stage-level encoder tensors (no per-block index).
pub const ENCODER_STAGE_ROLES: &[&str] = &[
    "conv1.weight",
    "conv1.bias",
    "conv2.weight",
    "conv2.bias",
    "pos_embed.weight",
    "ln_final.weight",
    "ln_final.bias",
];

/// Stage-level decoder tensors (no per-block index).
/// LM head is intentionally omitted: Whisper ties it to `token_embed`.
pub const DECODER_STAGE_ROLES: &[&str] = &[
    "token_embed.weight",
    "pos_embed.weight",
    "ln_final.weight",
    "ln_final.bias",
];

/// Pre-resolved tensor names for a single transformer block.
///
/// The hot path can index into [`Self::names`] directly instead of calling
/// [`whisper_tensor_name`] (and the `format!` allocation it implies) on
/// every fetch. Order tracks [`ENCODER_BLOCK_ROLES`] / [`DECODER_BLOCK_ROLES`]
/// depending on how the block was constructed.
#[derive(Debug, Clone)]
pub struct WhisperBlockAddresses {
    /// Fully-qualified `.knot` tensor names, one per role.
    pub names: Vec<String>,
}

impl WhisperBlockAddresses {
    /// Build a block address set for a given stage / layer / role list.
    pub fn new(stage: &str, layer: usize, roles: &[&str]) -> Self {
        let names = roles
            .iter()
            .map(|role| whisper_tensor_name(stage, Some(layer), role))
            .collect();
        Self { names }
    }
}

/// Pre-computed tensor addresses for a complete Whisper model.
///
/// Analogous to [`crate::model::ResolvedLocs`] for the LLaMA-family loader:
/// the encoder/decoder forward passes look up each weight by index from this
/// struct rather than re-formatting strings every step.
#[derive(Debug, Clone)]
pub struct WhisperTensorAddresses {
    /// Stage-level encoder tensors (`encoder_<role>`), order tracks
    /// [`ENCODER_STAGE_ROLES`].
    pub encoder_stage: Vec<String>,
    /// One [`WhisperBlockAddresses`] per encoder layer.
    pub encoder_blocks: Vec<WhisperBlockAddresses>,
    /// Stage-level decoder tensors (`decoder_<role>`), order tracks
    /// [`DECODER_STAGE_ROLES`].
    pub decoder_stage: Vec<String>,
    /// One [`WhisperBlockAddresses`] per decoder layer.
    pub decoder_blocks: Vec<WhisperBlockAddresses>,
}

impl WhisperTensorAddresses {
    /// Pre-compute every tensor name implied by `config`.
    ///
    /// Allocates once at model-load time; no further string formatting is
    /// required for tensor fetches during inference.
    pub fn new(config: &WhisperConfig) -> Self {
        let encoder_stage = ENCODER_STAGE_ROLES
            .iter()
            .map(|role| whisper_tensor_name("encoder", None, role))
            .collect();
        let encoder_blocks = (0..config.encoder_layers)
            .map(|i| WhisperBlockAddresses::new("encoder", i, ENCODER_BLOCK_ROLES))
            .collect();
        let decoder_stage = DECODER_STAGE_ROLES
            .iter()
            .map(|role| whisper_tensor_name("decoder", None, role))
            .collect();
        let decoder_blocks = (0..config.decoder_layers)
            .map(|i| WhisperBlockAddresses::new("decoder", i, DECODER_BLOCK_ROLES))
            .collect();

        Self {
            encoder_stage,
            encoder_blocks,
            decoder_stage,
            decoder_blocks,
        }
    }

    /// Total number of tensor names the model will request from the backend.
    /// Useful for sanity-checking against a loaded `.knot` metadata block.
    pub fn total_names(&self) -> usize {
        self.encoder_stage.len()
            + self
                .encoder_blocks
                .iter()
                .map(|b| b.names.len())
                .sum::<usize>()
            + self.decoder_stage.len()
            + self
                .decoder_blocks
                .iter()
                .map(|b| b.names.len())
                .sum::<usize>()
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Tests
// ─────────────────────────────────────────────────────────────────────────────

#[cfg(test)]
mod tests {
    use super::*;
    use serde_json::json;

    #[test]
    fn default_config_is_whisper_tiny() {
        let c = WhisperConfig::default();
        assert_eq!(c.n_mels, 80);
        assert_eq!(c.n_audio_ctx, 1500);
        assert_eq!(c.encoder_layers, 4);
        assert_eq!(c.encoder_hidden_dim, 384);
        assert_eq!(c.encoder_heads, 6);
        assert_eq!(c.encoder_intermediate_size, 1536);
        assert_eq!(c.decoder_layers, 4);
        assert_eq!(c.decoder_hidden_dim, 384);
        assert_eq!(c.decoder_heads, 6);
        assert_eq!(c.decoder_intermediate_size, 1536);
        assert_eq!(c.n_text_ctx, 448);
        assert_eq!(c.vocab_size, 51865);
        assert!((c.eps - 1e-5).abs() < 1e-12);
    }

    #[test]
    fn parses_whisper_base_from_hf_style_json() {
        // whisper-base: 6 encoder + 6 decoder layers, hidden 512, 8 heads.
        let meta = json!({
            "config": {
                "num_mel_bins": 80,
                "max_source_positions": 1500,
                "encoder_layers": 6,
                "d_model": 512,
                "encoder_attention_heads": 8,
                "encoder_ffn_dim": 2048,
                "decoder_layers": 6,
                "decoder_attention_heads": 8,
                "decoder_ffn_dim": 2048,
                "max_target_positions": 448,
                "vocab_size": 51865,
                "layer_norm_eps": 1e-5
            }
        });
        let c = parse_whisper_config(&meta).expect("parse ok");
        assert_eq!(c.encoder_layers, 6);
        assert_eq!(c.decoder_layers, 6);
        assert_eq!(c.encoder_hidden_dim, 512);
        assert_eq!(c.decoder_hidden_dim, 512);
        assert_eq!(c.encoder_heads, 8);
        assert_eq!(c.decoder_heads, 8);
        assert_eq!(c.encoder_intermediate_size, 2048);
        assert_eq!(c.decoder_intermediate_size, 2048);
        assert_eq!(c.n_audio_ctx, 1500);
        assert_eq!(c.n_text_ctx, 448);
    }

    #[test]
    fn parses_camelcase_keys_too() {
        // Tolerance check: a converter that emitted camelCase still works.
        let meta = json!({
            "config": {
                "encoderLayers": 12,
                "dModel": 768,
                "encoderAttentionHeads": 12,
                "decoderLayers": 12,
                "decoderAttentionHeads": 12,
            }
        });
        let c = parse_whisper_config(&meta).expect("parse ok");
        assert_eq!(c.encoder_layers, 12);
        assert_eq!(c.encoder_hidden_dim, 768);
        assert_eq!(c.encoder_heads, 12);
        // Defaults filled in for unspecified fields.
        assert_eq!(c.encoder_intermediate_size, 4 * 768);
        assert_eq!(c.decoder_hidden_dim, 768);
    }

    #[test]
    fn tensor_name_composition() {
        assert_eq!(
            whisper_tensor_name("encoder", Some(0), "attn_q.weight"),
            "encoder_blk_0_attn_q.weight"
        );
        assert_eq!(
            whisper_tensor_name("decoder", Some(3), "cross_v.weight"),
            "decoder_blk_3_cross_v.weight"
        );
        assert_eq!(
            whisper_tensor_name("encoder", None, "ln_final.bias"),
            "encoder_ln_final.bias"
        );
        assert_eq!(
            whisper_tensor_name("decoder", None, "token_embed.weight"),
            "decoder_token_embed.weight"
        );
    }

    #[test]
    fn addresses_pre_compute_expected_counts() {
        let cfg = WhisperConfig::default(); // tiny: 4 enc + 4 dec layers
        let addrs = WhisperTensorAddresses::new(&cfg);

        // One block-address set per layer.
        assert_eq!(addrs.encoder_blocks.len(), 4);
        assert_eq!(addrs.decoder_blocks.len(), 4);

        // Per-block role counts match the canonical role tables.
        let enc_per_block = ENCODER_BLOCK_ROLES.len();
        let dec_per_block = DECODER_BLOCK_ROLES.len();
        for blk in &addrs.encoder_blocks {
            assert_eq!(blk.names.len(), enc_per_block);
        }
        for blk in &addrs.decoder_blocks {
            assert_eq!(blk.names.len(), dec_per_block);
        }

        // Stage-level tensor counts.
        assert_eq!(addrs.encoder_stage.len(), ENCODER_STAGE_ROLES.len());
        assert_eq!(addrs.decoder_stage.len(), DECODER_STAGE_ROLES.len());

        // Spot-check one pre-formatted name to lock in the convention.
        assert_eq!(
            addrs.encoder_blocks[0].names[0],
            "encoder_blk_0_attn_q.weight"
        );
        assert_eq!(
            addrs.decoder_blocks[3].names[0],
            "decoder_blk_3_self_q.weight"
        );

        // Total = stage + blocks * roles, both sides.
        let expected_total = ENCODER_STAGE_ROLES.len()
            + cfg.encoder_layers * enc_per_block
            + DECODER_STAGE_ROLES.len()
            + cfg.decoder_layers * dec_per_block;
        assert_eq!(addrs.total_names(), expected_total);
    }
}
